// Simular OCR - extraer datos básicos
const filename = $('Webhook').first().json.filename || 'unknown.pdf';
const provider = $('Webhook').first().json.provider || 'unknown';

// Datos simulados basados en el proveedor
let invoiceData = {
  invoice_number: 'INV-' + Math.floor(Math.random() * 100000),
  date: new Date().toISOString().split('T')[0],
  supplier: provider,
  total: (Math.random() * 1000 + 100).toFixed(2),
  currency: 'EUR',
  items: [
    {
      description: 'Servicio profesional',
      quantity: 1,
      unit_price: (Math.random() * 500 + 50).toFixed(2),
      total: (Math.random() * 500 + 50).toFixed(2)
    }
  ]
};

// Enmascarar datos sensibles
if (invoiceData.supplier && invoiceData.supplier.toLowerCase().includes('antonio')) {
  invoiceData.supplier = invoiceData.supplier.replace(/antonio/gi, 'A***o');
}

const result = {
  success: true,
  timestamp: new Date().toISOString(),
  source: 'simulated-ocr',
  data: invoiceData,
  original_filename: filename
};

return [result];
